RuleSet.GenFile:
--
--	@(#) $GenPackageDir$/$GenFileName$
$MssDoubleDashScriptLicense$
create or replace function $lower DbSchemaName$.$sp_read_dbtablename_cc_all$($implPgSqlSPStandardArgs$ )
returns setof $lower DbSchemaName$.$type_dbschemaname_cc_rec$ as $$$$$switch SecScope None empty System empty Cluster implPgSqlSPReadTableDeclPermFlag Tenant implPgSqlSPReadTableDeclPermFlag default error$
begin$poptop Table switch TableName Cluster empty Tenant empty SecUser empty default implPgSqlSPReadEnforceSec$$switch SecScope None implPgSqlSPReadTableCCAllRetSelectSystem System implPgSqlSPReadTableCCAllRetSelectSystem Cluster implPgSqlSPReadTableCCAllRetSelectRestrictCluster Tenant implPgSqlSPReadTableCCAllRetSelectRestrictTenant default error$
	return;
end;
$$$$ language plpgsql;

RuleSet.GenRule:
if( isSystemUser )
then
	return query select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ as $lower ClassCode$$switch HasSuperClassRelation yes implPgSqlClassCodeJoinSuperTable default empty$
	order by ClassCode asc;
else
	return query select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ as $lower ClassCode$$switch HasSuperClassRelation yes implPgSqlClassCodeJoinSuperTable default empty$$implPgSqlSPReadTableRetSelectWhereRestrictCluster$;
end if;

if( isSystemUser )
then
	return query select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ as $lower ClassCode$$switch HasSuperClassRelation yes implPgSqlClassCodeJoinSuperTable default empty$
	order by ClassCode asc;
else
	return query select
		distinct( $lower poptop Table reference BaseClass ClassCode$.ClassCode ) as ClassCode
	from $lower DbSchemaName$.$DbTableName$ as $lower ClassCode$$switch HasSuperClassRelation yes implPgSqlClassCodeJoinSuperTable default empty$$implPgSqlSPReadTableRetSelectWhereRestrictTenant$;
end if;
